import { create } from "zustand";
import { persist, createJSONStorage } from "zustand/middleware";
import { Product } from "../types";

type CartItem = Product & { quantity: number };

interface CartState {
  items: CartItem[];
  addToCart: (product: Product) => void;
  removeFromCart: (id: string) => void;
  increaseQuantity: (id: string) => void;
  decreaseQuantity: (id: string) => void;
  clearCart: () => void;
}

export const useCartStore = create<CartState>()(
  persist(
    (set) => ({
      items: [],
      addToCart: (product) => {
        console.log("CartStore: додаємо товар", product.title, "ID:", product.id);
        set((state) => {
          const existing = state.items.find((item) => item.id === product.id);
          if (!existing) {
            // Якщо товару ще немає — додаємо новий
            const newItems = [...state.items, { ...product, quantity: 1 }];
            console.log("Товар додано, новий кошик:", newItems.map(i => i.title));
            return { items: newItems };
          }
          if (existing.quantity < product.stock) {
            // Якщо ще не досягли stock — збільшуємо кількість
            const updatedItems = state.items.map((item) =>
              item.id === product.id
                ? { ...item, quantity: item.quantity + 1 }
                : item
            );
            console.log("Кількість збільшено:", existing.title, "нова кількість:", existing.quantity + 1);
            return { items: updatedItems };
          }
          console.log("Досягнуто ліміту stock для", product.title);
          return { items: state.items };
        });
      },
      removeFromCart: (id) =>
        set((state) => ({
          items: state.items.filter((item) => item.id !== id),
        })),
      increaseQuantity: (id) =>
        set((state) => ({
          items: state.items.map((item) =>
            item.id === id && item.quantity < item.stock
              ? { ...item, quantity: item.quantity + 1 }
              : item
          ),
        })),
      decreaseQuantity: (id) =>
        set((state) => ({
          items: state.items
            .map((item) =>
              item.id === id
                ? { ...item, quantity: item.quantity - 1 }
                : item
            )
            .filter((item) => item.quantity > 0), // Видаляємо, якщо кількість стала 0
        })),
      clearCart: () => set({ items: [] }),
    }),
    {
      name: 'cart-storage', // Ім'я ключа у localStorage
      storage: createJSONStorage(() => localStorage),
    }
  )
);